pub(crate) fn translate_pl(en: &str) -> &str {
    lookup_pl(en).unwrap_or(en)
}

#[cfg(test)]
pub(crate) fn has_translation_pl(en: &str) -> bool {
    lookup_pl(en).is_some()
}

