pub(crate) fn translate_ru(en: &str) -> &str {
    lookup_ru(en).unwrap_or(en)
}

#[cfg(test)]
pub(crate) fn has_translation_ru(en: &str) -> bool {
    lookup_ru(en).is_some()
}

